137	/// Return the XDG/FreeDesktop icon name for a given daemon state.
138	///
139	/// `None` means the daemon is not running — treat the same as Muted so the
140	/// tray icon makes it obvious the mic is inactive.  `Listening` gets a
141	/// distinct "high" variant to distinguish the wake-word window from idle.
142	pub(crate) fn icon_name_for_state(state: Option<&DaemonState>) -> &'static str {
143	    match state {
144	        None | Some(DaemonState::Muted) => "audio-input-microphone-muted",
145	        Some(DaemonState::Idle) | Some(DaemonState::Recording) => "audio-input-microphone",
146	        Some(DaemonState::Listening) => "audio-input-microphone-high",
147	    }
148	}
