152	struct VibeTray {
153	    open_window: Arc<AtomicBool>,
154	    state: Arc<Mutex<TrayState>>,
155	}
156	
157	impl VibeTray {
158	    fn current_state(&self) -> TrayState {
159	        self.state
160	            .try_lock()
161	            .map(|s| s.clone())
162	            .unwrap_or_default()
163	    }
164	}
