166	impl Tray for VibeTray {
167	    fn id(&self) -> String {
168	        "vibe-attack".into()
169	    }
170	
171	    fn icon_name(&self) -> String {
172	        icon_name_for_state(self.current_state().daemon_state.as_ref()).into()
173	    }
174	
175	    fn title(&self) -> String {
176	        "Vibe Attack".into()
177	    }
178	
179	    fn tool_tip(&self) -> ksni::ToolTip {
180	        let description = match self.current_state().daemon_state {
181	            None => "Not running".into(),
182	            Some(DaemonState::Idle) => "Idle — listening for wake word".into(),
183	            Some(DaemonState::Muted) => "Muted".into(),
184	            Some(DaemonState::Listening) => "Listening…".into(),
185	            Some(DaemonState::Recording) => "Recording…".into(),
186	        };
187	        ksni::ToolTip {
188	            title: "Vibe Attack".into(),
189	            description,
190	            ..Default::default()
191	        }
192	    }
193	
194	    fn menu(&self) -> Vec<MenuItem<Self>> {
195	        let state = self.current_state();
196	        let is_muted = matches!(state.daemon_state, Some(DaemonState::Muted));
197	        let daemon_running = state.daemon_state.is_some();
198	
199	        let open_flag = Arc::clone(&self.open_window);
200	
201	        let mut items: Vec<MenuItem<Self>> = Vec::new();
202	
203	        items.push(
204	            StandardItem {
205	                label: "Open Config".into(),
206	                icon_name: "preferences-system".into(),
207	                activate: Box::new(move |_this: &mut Self| {
208	                    open_flag.store(true, Ordering::Release);
209	                }),
210	                ..Default::default()
211	            }
212	            .into(),
213	        );
214	
215	        items.push(MenuItem::Separator);
216	
217	        if daemon_running {
218	            let mute_label = if is_muted { "Unmute" } else { "Mute" };
219	            let mute_icon = if is_muted {
220	                "audio-input-microphone"
221	            } else {
222	                "audio-input-microphone-muted"
223	            };
224	            items.push(
225	                StandardItem {
226	                    label: mute_label.into(),
227	                    icon_name: mute_icon.into(),
228	                    activate: Box::new(move |_this: &mut Self| {
229	                        let cmd = if is_muted {
230	                            ControlRequest::Unmute
231	                        } else {
232	                            ControlRequest::Mute
233	                        };
234	                        // Fire-and-forget on a fresh thread — ksni callbacks must not block.
235	                        std::thread::spawn(move || {
236	                            let _ = send_command(cmd);
237	                        });
238	                    }),
239	                    ..Default::default()
240	                }
241	                .into(),
242	            );
243	            items.push(MenuItem::Separator);
244	        }
245	
246	        // Profile switcher submenu — always shown, disabled when daemon is not running.
247	        let profile_submenu: Vec<MenuItem<Self>> = state
248	            .profiles
249	            .iter()
250	            .map(|name| {
251	                let is_active = state.active_profile.as_deref() == Some(name.as_str());
252	                let name_clone = name.clone();
253	                CheckmarkItem {
254	                    label: name.clone(),
255	                    checked: is_active,
256	                    enabled: daemon_running,
257	                    activate: Box::new(move |_this: &mut Self| {
258	                        let req = ControlRequest::SwitchProfile {
259	                            name: name_clone.clone(),
260	                        };
261	                        std::thread::spawn(move || {
262	                            let _ = send_command(req);
263	                        });
264	                    }),
265	                    ..Default::default()
266	                }
267	                .into()
268	            })
269	            .collect();
270	
271	        items.push(
272	            SubMenu {
273	                label: "Profiles".into(),
274	                icon_name: "folder".into(),
275	                enabled: !state.profiles.is_empty(),
276	                submenu: profile_submenu,
277	                ..Default::default()
278	            }
279	            .into(),
280	        );
281	
282	        items.push(MenuItem::Separator);
283	
284	        items.push(
285	            StandardItem {
286	                label: "Quit".into(),
287	                icon_name: "application-exit".into(),
288	                activate: Box::new(|_| std::process::exit(0)),
289	                ..Default::default()
290	            }
291	            .into(),
292	        );
293	
294	        items
295	    }
296	}
