185	        let description = match self.current_state().daemon_state {
186	            None => "Not running".into(),
187	            Some(DaemonState::Idle) => "Idle — listening for wake word".into(),
188	            Some(DaemonState::Muted) => "Muted".into(),
189	            Some(DaemonState::Listening) => "Listening…".into(),
190	            Some(DaemonState::Recording) => "Recording…".into(),
